public long minCost(int[] nums, int[] cost) {
    long ans = Long.MAX_VALUE;
    int minValue = nums[0];

    for (int num : nums) {
        minValue = Math.min(minValue, num);
    }

    for (int target = minValue; target < minValue + 2; target++) {
        long local_res = 0;
        for (int i = 0; i < nums.length; i++) {
            local_res += Math.abs(nums[i] - target) * cost[i];
        }
        ans = Math.min(ans, local_res);
    }

    return ans;
}
```

